import json
import random
from typing import List, Dict, Optional
from datetime import datetime
import logging

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger(__name__)

class AdContentGenerator:
    """
    Generates advertising chat scenarios based on viral content principles.
    """

    TEMPLATES = {
        "before_after": [
            "Раньше было {before}, но теперь {after}!",
            "Как изменилась ситуация: было {before} → стало {after}",
            "{before}? Теперь это в прошлом! {after}"
        ],
        "expert_opinion": [
            "Эксперты в {niche} рекомендуют: {solution}",
            "По данным исследований в {niche}, {solution} дает {result}",
            "{expert} о {solution}: '{quote}'"
        ],
        "trend_challenge": [
            "Присоединяйся к тренду #{trend} в {niche}! {challenge}",
            "Все в {niche} делают {action}. А ты?",
            "Ты готов к {challenge}? В {niche} это новый тренд!"
        ]
    }

    STYLES = {
        "professional": {
            "tone": "уважительный",
            "words": ["рекомендуем", "эффективно", "результат", "исследования"]
        },
        "friendly": {
            "tone": "дружелюбный",
            "words": ["привет", "круто", "вау", "попробуй"]
        },
        "urgent": {
            "tone": "срочный",
            "words": ["сейчас", "успей", "ограничено", "последний шанс"]
        }
    }

    def __init__(self, template_file: str = "src/chat_scenarios/ad_chat_template.json"):
        self.template = self._load_template(template_file)

    def _load_template(self, path: str) -> Dict:
        """Load JSON template file"""
        try:
            with open(path, 'r', encoding='utf-8') as f:
                return json.load(f)
        except Exception as e:
            logger.error(f"Error loading template: {e}")
            raise

    def generate_scene(self, elements: List[str], style: str = "professional") -> Dict:
        """
        Generate a scene based on viral elements and style.

        Args:
            elements: List of viral elements (e.g., ["visuals", "emotion", "trend"])
            style: One of "professional", "friendly", "urgent"

        Returns:
            Dictionary with generated scene content
        """
        if style not in self.STYLES:
            raise ValueError(f"Invalid style. Choose from: {list(self.STYLES.keys())}")

        scene_type = random.choice(["before_after", "expert_opinion", "trend_challenge"])
        template = random.choice(self.TEMPLATES[scene_type])

        # Fill template based on scene type
        if scene_type == "before_after":
            content = template.format(
                before=random.choice(["проблемы", "сложности", "ограничения"]),
                after=random.choice(["решение", "успех", "прорыв"])
            )
        elif scene_type == "expert_opinion":
            content = template.format(
                niche=random.choice(elements),
                solution="наш метод",
                result="+30% эффективности",
                expert="эксперт",
                quote="Это изменит ваш подход!"
            )
        else:
            content = template.format(
                trend=random.choice(elements),
                niche="вашей нише",
                challenge="испытай себя",
                action="это"
            )

        # Apply style
        style_words = self.STYLES[style]["words"]
        for word in style_words:
            if word not in content.lower():
                content += f" {random.choice(style_words)}!"
                break

        return {
            "content": content,
            "type": "string",
            "style": style,
            "elements": elements,
            "template": scene_type,
            "generated_at": datetime.now().isoformat()
        }

